import React from 'react';

interface CardProps {
  children?: React.ReactNode;
  className?: string;
  padding?: boolean;
  title?: string;
}

const Card = ({ children, className = '', padding = true, title }: CardProps): JSX.Element => {
  return (
    <div className={`card ${padding ? 'p-6' : ''} ${className}`}>
      {title && (
        <h3 className="text-lg font-semibold text-gray-900 mb-4">{title}</h3>
      )}
      <div>{children}</div>
    </div>
  );
};

export default Card;
